{
  "name": "SonicSage: Production Knowledge Base",
  "description": "A high-end electronic music production guiding tool that provides expert mixing chains, plugin settings, and DAW-specific stock alternatives based on genre and target effects."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Setting {
  knob: string;
  value: string;
}

export interface PluginDetail {
  id: string;
  name: string;
  category: string;
  purpose: string;
  settings: Setting[];
  alternative: string;
  isStock: boolean;
}

export interface ProductionGuidance {
  introduction: string;
  chain: PluginDetail[];
  proTips: string[];
}

export type DAW = 'Ableton Live' | 'Logic Pro' | 'FL Studio' | 'Studio One' | 'Cubase' | 'Bitwig';
export type Genre = 'House' | 'Melodic House' | 'Deep House' | 'Tech House' | 'Techno' | 'Garage' | 'Afro House' | 'Disco House';
export type MixArea = 'Drum Bus' | 'Kick Drum' | 'Snare/Clap' | 'Vocals' | 'Bassline' | 'Master Bus' | 'Synths';
export type EffectGoal = 'Punchy' | 'Warm/Analog' | 'Clean/Transparent' | 'Aggressive' | 'Beefy Low End' | 'Wide Stereo' | 'Clarity/Air';

export interface SelectionState {
  daw: DAW;
  genre: Genre;
  area: MixArea;
  effect: EffectGoal;
}

import { DAW, Genre, MixArea, EffectGoal } from './types';

export const DAWS: DAW[] = ['Ableton Live', 'Logic Pro', 'FL Studio', 'Studio One', 'Cubase', 'Bitwig'];

export const GENRES: Genre[] = [
  'House', 'Melodic House', 'Deep House', 'Tech House', 'Techno', 'Garage', 'Afro House', 'Disco House'
];

export const MIX_AREAS: MixArea[] = [
  'Drum Bus', 'Kick Drum', 'Snare/Clap', 'Vocals', 'Bassline', 'Master Bus', 'Synths'
];

export const EFFECT_GOALS: EffectGoal[] = [
  'Punchy', 'Warm/Analog', 'Clean/Transparent', 'Aggressive', 'Beefy Low End', 'Wide Stereo', 'Clarity/Air'
];

import { GoogleGenAI, Type } from "@google/genai";
import { SelectionState, ProductionGuidance } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getProductionGuidance = async (state: SelectionState): Promise<ProductionGuidance> => {
  const { daw, genre, area, effect } = state;

  const prompt = `You are a world-class electronic music mix engineer.
Generate a professional mixing guidance for:
DAW: ${daw}
Genre: ${genre}
Area: ${area}
Effect Goal: ${effect}

Provide a step-by-step plugin chain (3-5 plugins) including specific settings and stock alternatives for ${daw}.
Ensure the advice is technical and accurate for professional production.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          introduction: {
            type: Type.STRING,
            description: "A short technical overview of why this chain is selected."
          },
          chain: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                category: { type: Type.STRING },
                purpose: { type: Type.STRING },
                isStock: { type: Type.BOOLEAN },
                alternative: { type: Type.STRING, description: "A high-end 3rd party alternative if the plugin is stock, or vice versa." },
                settings: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      knob: { type: Type.STRING },
                      value: { type: Type.STRING }
                    },
                    required: ["knob", "value"]
                  }
                }
              },
              required: ["id", "name", "category", "purpose", "isStock", "settings", "alternative"]
            }
          },
          proTips: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Additional tips for fine-tuning the sound."
          }
        },
        required: ["introduction", "chain", "proTips"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

import React from 'react';

interface DropdownProps<T extends string> {
  label: string;
  options: T[];
  value: T;
  onChange: (value: T) => void;
}

export const Dropdown = <T extends string,>({ label, options, value, onChange }: DropdownProps<T>) => {
  return (
    <div className="flex flex-col gap-1.5 w-full">
      <label className="text-xs font-bold uppercase tracking-wider text-slate-500 ml-1">
        {label}
      </label>
      <select
        value={value}
        onChange={(e) => onChange(e.target.value as T)}
        className="bg-slate-900 border border-slate-800 text-slate-200 rounded-lg px-3 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 transition-all cursor-pointer hover:bg-slate-800/80"
      >
        {options.map((opt) => (
          <option key={opt} value={opt}>
            {opt}
          </option>
        ))}
      </select>
    </div>
  );
};

import React from 'react';
import { PluginDetail } from '../types';

interface PluginNodeProps {
  plugin: PluginDetail;
  isActive: boolean;
  onClick: () => void;
  index: number;
}

export const PluginNode: React.FC<PluginNodeProps> = ({ plugin, isActive, onClick, index }) => {
  return (
    <div className="flex items-center group">
      {/* Signal path line */}
      {index > 0 && <div className="w-8 h-px bg-slate-700 group-hover:bg-indigo-500 transition-colors" />}

      <button
        onClick={onClick}
        className={`relative flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all duration-300 w-48 h-32 hover:scale-105 ${
          isActive 
            ? 'bg-indigo-900/40 border-indigo-400 shadow-[0_0_20px_rgba(129,140,248,0.2)]' 
            : 'bg-slate-900 border-slate-800 hover:border-slate-600'
        }`}
      >
        <div className="absolute top-2 right-2 flex gap-1">
           {plugin.isStock && (
             <span className="text-[10px] px-1.5 py-0.5 rounded bg-slate-800 text-slate-400 font-bold uppercase tracking-tighter">
               Stock
             </span>
           )}
        </div>

        <div className={`text-xs font-mono mb-1 ${isActive ? 'text-indigo-300' : 'text-slate-500'}`}>
          {plugin.category}
        </div>

        <div className="text-sm font-bold text-center leading-tight mb-2 truncate w-full px-2">
          {plugin.name}
        </div>

        <div className="flex gap-1 justify-center">
          {Array.from({ length: 3 }).map((_, i) => (
            <div 
              key={i} 
              className={`w-3 h-3 rounded-full border border-slate-700 ${isActive ? 'bg-indigo-500/50' : 'bg-slate-800'}`} 
            />
          ))}
        </div>

        {isActive && (
           <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-8 h-1 bg-indigo-400 rounded-full" />
        )}
      </button>
    </div>
  );
};

import React from 'react';
import { PluginDetail } from '../types';

interface PluginInspectorProps {
  plugin: PluginDetail | null;
}

export const PluginInspector: React.FC<PluginInspectorProps> = ({ plugin }) => {
  if (!plugin) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-slate-600 p-8 text-center border-l border-slate-800 bg-slate-900/50">
        <svg xmlns="http://www.w3.org/2000/svg" className="w-12 h-12 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
        <p className="text-sm">Click a plugin in the chain to view technical settings and alternatives.</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col border-l border-slate-800 bg-slate-900 overflow-y-auto">
      <div className="p-6 border-b border-slate-800 bg-slate-900/80 sticky top-0 backdrop-blur-md z-10">
        <h3 className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-1">{plugin.category}</h3>
        <h2 className="text-2xl font-bold text-white tracking-tight">{plugin.name}</h2>
      </div>

      <div className="p-6 space-y-8">
        <section>
          <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Objective</h4>
          <p className="text-slate-300 leading-relaxed text-sm">{plugin.purpose}</p>
        </section>

        <section>
          <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-4">Recommended Settings</h4>
          <div className="grid grid-cols-1 gap-3">
            {plugin.settings.map((s, i) => (
              <div key={i} className="flex items-center justify-between p-3 rounded-lg bg-slate-800/50 border border-slate-700/50">
                <span className="text-sm font-medium text-slate-400">{s.knob}</span>
                <span className="mono text-xs text-indigo-300 font-bold bg-indigo-500/10 px-2 py-1 rounded border border-indigo-500/20">{s.value}</span>
              </div>
            ))}
          </div>
        </section>

        <section className="pt-4 border-t border-slate-800">
          <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">
            {plugin.isStock ? 'Professional Upgrade' : 'Stock Alternative'}
          </h4>
          <div className="p-4 rounded-xl bg-gradient-to-br from-indigo-900/20 to-slate-800 border border-indigo-500/20">
            <p className="text-sm font-semibold text-white mb-1">{plugin.alternative}</p>
            <p className="text-xs text-slate-400">Achieves identical results with {plugin.isStock ? 'enhanced precision' : 'low CPU overhead'}.</p>
          </div>
        </section>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { DAW, Genre, MixArea, EffectGoal, SelectionState, ProductionGuidance, PluginDetail } from './types';
import { DAWS, GENRES, MIX_AREAS, EFFECT_GOALS } from './constants';
import { Dropdown } from './components/Dropdown';
import { PluginNode } from './components/PluginNode';
import { PluginInspector } from './components/PluginInspector';
import { getProductionGuidance } from './services/geminiService';

const App: React.FC = () => {
  const [selection, setSelection] = useState<SelectionState>({
    daw: 'Ableton Live',
    genre: 'Melodic House',
    area: 'Drum Bus',
    effect: 'Punchy',
  });

  const [guidance, setGuidance] = useState<ProductionGuidance | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedPluginId, setSelectedPluginId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    setIsLoading(true);
    setError(null);
    setSelectedPluginId(null);
    try {
      const result = await getProductionGuidance(selection);
      setGuidance(result);
    } catch (err) {
      console.error(err);
      setError("Failed to generate production chain. Please check your network or try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const selectedPlugin = guidance?.chain.find(p => p.id === selectedPluginId) || null;

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="h-16 border-b border-slate-800 bg-slate-950/50 backdrop-blur-md flex items-center px-6 justify-between shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded bg-indigo-600 flex items-center justify-center font-black text-white italic">SS</div>
          <h1 className="font-bold text-xl tracking-tighter text-white">Sonic<span className="text-indigo-500">Sage</span></h1>
        </div>
        <div className="text-[10px] mono text-slate-500 bg-slate-900 px-2 py-1 rounded border border-slate-800 uppercase tracking-widest font-bold">
          AI-Powered Production Brain
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        {/* Main Content */}
        <main className="flex-1 flex flex-col overflow-y-auto">
          {/* Controls Bar */}
          <div className="bg-slate-900/50 border-b border-slate-800 p-6">
            <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
              <Dropdown label="DAW" options={DAWS} value={selection.daw} onChange={(v) => setSelection(prev => ({ ...prev, daw: v }))} />
              <Dropdown label="Genre" options={GENRES} value={selection.genre} onChange={(v) => setSelection(prev => ({ ...prev, genre: v }))} />
              <Dropdown label="Target Area" options={MIX_AREAS} value={selection.area} onChange={(v) => setSelection(prev => ({ ...prev, area: v }))} />
              <Dropdown label="Effect Goal" options={EFFECT_GOALS} value={selection.effect} onChange={(v) => setSelection(prev => ({ ...prev, effect: v }))} />

              <div className="md:col-start-4">
                <button
                  onClick={handleGenerate}
                  disabled={isLoading}
                  className={`w-full py-3 rounded-lg font-bold uppercase tracking-widest text-sm transition-all shadow-lg active:scale-95 ${
                    isLoading 
                    ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                    : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-600/20'
                  }`}
                >
                  {isLoading ? 'Processing...' : 'Generate Guidance'}
                </button>
              </div>
            </div>
          </div>

          {/* Results Area */}
          <div className="flex-1 p-8 bg-[#0d0d11]">
            <div className="max-w-6xl mx-auto">
              {isLoading ? (
                <div className="flex flex-col items-center justify-center py-20 animate-pulse">
                  <div className="w-16 h-16 border-4 border-indigo-600/30 border-t-indigo-600 rounded-full animate-spin mb-6" />
                  <p className="text-slate-400 font-medium">Analyzing verified production techniques...</p>
                </div>
              ) : error ? (
                <div className="p-6 rounded-xl bg-red-950/20 border border-red-900/50 text-red-400 text-center">
                  {error}
                </div>
              ) : guidance ? (
                <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
                  {/* Summary */}
                  <div className="max-w-3xl">
                    <h2 className="text-3xl font-bold text-white mb-4 leading-tight">Expert Strategy for {selection.area}</h2>
                    <p className="text-slate-400 leading-relaxed italic border-l-2 border-indigo-600 pl-6 py-2">
                      {guidance.introduction}
                    </p>
                  </div>

                  {/* Chain Visualizer */}
                  <section>
                    <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Plugin Signal Chain</h3>
                    <div className="bg-slate-900/30 border border-slate-800 rounded-2xl p-8 overflow-x-auto">
                      <div className="flex items-center min-w-max">
                         <div className="flex flex-col items-center gap-2">
                           <div className="w-10 h-10 rounded-full border border-indigo-500 flex items-center justify-center text-indigo-400 font-bold bg-indigo-500/10">IN</div>
                         </div>
                         <div className="w-8 h-px bg-slate-700" />

                         <div className="flex items-center">
                           {guidance.chain.map((plugin, idx) => (
                             <PluginNode 
                                key={plugin.id} 
                                plugin={plugin} 
                                index={idx}
                                isActive={selectedPluginId === plugin.id}
                                onClick={() => setSelectedPluginId(plugin.id)}
                             />
                           ))}
                         </div>

                         <div className="w-8 h-px bg-slate-700" />
                         <div className="flex flex-col items-center gap-2">
                           <div className="w-10 h-10 rounded-full border border-indigo-500 flex items-center justify-center text-indigo-400 font-bold bg-indigo-500/10">OUT</div>
                         </div>
                      </div>
                    </div>
                  </section>

                  {/* Pro Tips */}
                  <section className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-20">
                    <div className="space-y-4">
                      <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Industry Pro Tips</h3>
                      <div className="space-y-3">
                        {guidance.proTips.map((tip, i) => (
                          <div key={i} className="p-4 rounded-xl bg-slate-900 border border-slate-800 flex gap-4">
                            <span className="text-indigo-500 font-bold">0{i+1}</span>
                            <p className="text-sm text-slate-300 leading-relaxed">{tip}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  </section>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-32 text-slate-600">
                   <div className="w-24 h-24 mb-6 rounded-full border-2 border-slate-800 border-dashed flex items-center justify-center">
                     <svg xmlns="http://www.w3.org/2000/svg" className="w-10 h-10 opacity-30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9 9l10.5-3m0 6.553v3.75a2.25 2.25 0 01-1.632 2.163l-1.32.377a1.803 1.803 0 11-.99-3.467l2.31-.66a2.25 2.25 0 001.632-2.163zm0 0V2.25L9 5.25v10.303m0 0v3.75a2.25 2.25 0 01-1.632 2.163l-1.32.377a1.803 1.803 0 01-.99-3.467l2.31-.66A2.25 2.25 0 009 15.553z" />
                     </svg>
                   </div>
                   <h2 className="text-lg font-medium mb-1 text-slate-400">Ready to mix?</h2>
                   <p className="text-sm max-w-sm text-center">Select your DAW and genre to get custom processing advice for your track.</p>
                </div>
              )}
            </div>
          </div>
        </main>

        {/* Sidebar Inspector */}
        <aside className="w-96 shrink-0 hidden lg:block">
          <PluginInspector plugin={selectedPlugin} />
        </aside>
      </div>
    </div>
  );
};

export default App;

export interface Setting {
  knob: string;
  value: string;
}

export interface PluginDetail {
  id: string;
  name: string;
  category: string;
  purpose: string;
  settings: Setting[];
  alternative: string;
  isStock: boolean;
}

export interface ProductionGuidance {
  introduction: string;
  chain: PluginDetail[];
  proTips: string[];
}

