{
  "name": "MixBrain: Pro Production Knowledge Base",
  "description": "A high-end electronic music production guiding tool with a vibrant aesthetic. Expert mixing chains, plugin settings, and stock alternatives.",
  "requestFramePermissions": []
}

export interface Setting {
  knob: string;
  value: string;
}

export interface PluginDetail {
  id: string;
  name: string;
  category: string;
  icon: 'eq' | 'comp' | 'reverb' | 'delay' | 'dist' | 'util' | 'limiting';
  purpose: string;
  settings: Setting[];
  alternative: string;
  alternativeUrl: string;
  isStock: boolean;
}

export interface ProductionGuidance {
  introduction: string;
  chain: PluginDetail[];
  proTips: string[];
}

export type DAW = 'Ableton Live' | 'Logic Pro' | 'FL Studio' | 'Studio One' | 'Cubase' | 'Bitwig';
export type Genre = 'House' | 'Melodic House' | 'Deep House' | 'Tech House' | 'Techno' | 'Garage' | 'Afro House' | 'Disco House';
export type MixArea = 'Drum Bus' | 'Kick Drum' | 'Snare/Clap' | 'Vocals' | 'Bassline' | 'Master Bus' | 'Synths';
export type EffectGoal = 'Punchy' | 'Warm/Analog' | 'Clean/Transparent' | 'Aggressive' | 'Beefy Low End' | 'Wide Stereo' | 'Clarity/Air' | 'Polished Final Master';

export interface SelectionState {
  daw: DAW;
  genre: Genre;
  area: MixArea;
  effect: EffectGoal;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SelectionState, ProductionGuidance } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getProductionGuidance = async (state: SelectionState): Promise<ProductionGuidance> => {
  const { daw, genre, area, effect } = state;

  const prompt = `You are a world-class electronic music mix engineer.
Generate professional mixing guidance for:
DAW: ${daw}
Genre: ${genre}
Area: ${area}
Effect Goal: ${effect}

Provide a step-by-step plugin chain (3-5 plugins) including specific settings and stock alternatives for ${daw}.
For each plugin, select the most relevant icon type from: eq, comp, reverb, delay, dist, util, limiting.
For the 'alternativeUrl', provide a direct link to the official manufacturer's product page for the alternative plugin (e.g., FabFilter, Soundtoys, Waves, etc.).
Ensure the advice is technical and accurate for professional production.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          introduction: {
            type: Type.STRING,
            description: "A short technical overview of why this chain is selected."
          },
          chain: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                category: { type: Type.STRING },
                icon: { type: Type.STRING, description: "One of: eq, comp, reverb, delay, dist, util, limiting" },
                purpose: { type: Type.STRING },
                isStock: { type: Type.BOOLEAN },
                alternative: { type: Type.STRING },
                alternativeUrl: { type: Type.STRING, description: "The direct URL to the alternative plugin's website." },
                settings: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      knob: { type: Type.STRING },
                      value: { type: Type.STRING }
                    },
                    required: ["knob", "value"]
                  }
                }
              },
              required: ["id", "name", "category", "icon", "purpose", "isStock", "settings", "alternative", "alternativeUrl"]
            }
          },
          proTips: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Additional tips for fine-tuning the sound."
          }
        },
        required: ["introduction", "chain", "proTips"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

