import { GoogleGenAI, Type } from "@google/genai";
import { SelectionState, ProductionGuidance } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getProductionGuidance = async (state: SelectionState): Promise<ProductionGuidance> => {
  const { daw, genre, area, effect } = state;

  const prompt = `You are a world-class electronic music mix engineer.
Generate professional mixing guidance for:
DAW: ${daw}
Genre: ${genre}
Area: ${area}
Effect Goal: ${effect}

Provide a step-by-step plugin chain (3-5 plugins) including specific settings and stock alternatives for ${daw}.
For each plugin, select the most relevant icon type from: eq, comp, reverb, delay, dist, util, limiting.
For the 'alternativeUrl', provide a direct link to the official manufacturer's product page for the alternative plugin (e.g., FabFilter, Soundtoys, Waves, etc.).
For 'visualPrompt', write a highly descriptive prompt for an image generation model that depicts the high-end professional alternative plugin's interface. It should describe the plugin's knobs, meters, or curves (like an EQ curve or compression transfer graph) based on the settings provided.
For 'proTips', provide a concise summary and a detailed 2-3 sentence technical explanation of why this is important and how to execute it perfectly.
Ensure the advice is technical and accurate for professional production.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          introduction: {
            type: Type.STRING,
            description: "A short technical overview of why this chain is selected."
          },
          chain: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                category: { type: Type.STRING },
                icon: { type: Type.STRING, description: "One of: eq, comp, reverb, delay, dist, util, limiting" },
                purpose: { type: Type.STRING },
                isStock: { type: Type.BOOLEAN },
                alternative: { type: Type.STRING },
                alternativeUrl: { type: Type.STRING, description: "The direct URL to the alternative plugin's website." },
                visualPrompt: { type: Type.STRING, description: "A detailed prompt to generate an image of the Pro plugin UI." },
                settings: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      knob: { type: Type.STRING },
                      value: { type: Type.STRING }
                    },
                    required: ["knob", "value"]
                  }
                }
              },
              required: ["id", "name", "category", "icon", "purpose", "isStock", "settings", "alternative", "alternativeUrl", "visualPrompt"]
            }
          },
          proTips: {
            type: Type.ARRAY,
            items: { 
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["summary", "explanation"]
            },
            description: "Additional tips for fine-tuning the sound with technical depth."
          }
        },
        required: ["introduction", "chain", "proTips"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

export const generatePluginVisual = async (visualPrompt: string): Promise<string | null> => {
  try {
    const genAI = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const response = await genAI.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `High-resolution professional music production software UI screenshot. Minimalist dark mode aesthetic. Focus on ${visualPrompt}. Cyberpunk hot pink and cyan neon highlights. Highly detailed meters and knobs. Blurred studio background.`,
          },
        ],
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image generation failed:", error);
    return null;
  }
};

