                   </h4>
                   <div className="space-y-4">
                      <div>
                        <p className="text-[9px] text-white/30 uppercase font-black mb-1">Low End</p>
                        <p className="text-xs text-white/80 leading-snug">{report.frequencyAnalysis.lowEnd}</p>
                      </div>
