import { GoogleGenAI, Type } from "@google/genai";
import { SelectionState, ProductionGuidance, MixAnalysisReport, AnalysisGenre, AnalysisGoal, ScaleAnalysis, MusicalKey, MusicalScaleType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const generateSeed = (audioBase64: string, genre: string, goal: string): number => {
  const identityString = audioBase64.substring(0, 5000) + genre + goal;
  let hash = 0;
  for (let i = 0; i < identityString.length; i++) {
    const char = identityString.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash |= 0; 
  }
  return Math.abs(hash);
};

export const getProductionGuidance = async (state: SelectionState): Promise<ProductionGuidance> => {
  const { daw, genre, area, effect } = state;

  const prompt = `You are a world-class electronic music mix engineer and an expert in ${daw}.
Generate professional mixing guidance for:
DAW: ${daw}
Genre: ${genre}
Area: ${area}
Effect Goal: ${effect}

CRITICAL REQUIREMENT: The primary plugin 'chain' MUST use ONLY the built-in stock plugins provided by ${daw}. 
For each plugin in the chain:
1. 'name' must be the exact name of the stock plugin in ${daw} (e.g., 'Compressor', 'EQ Eight', 'Phat FX').
2. 'isStock' must be true.
3. 'alternative' must be a high-end 3rd party professional alternative (e.g., FabFilter Pro-Q 3, Soundtoys Decapitator, Waves SSL G-Master Buss Compressor).
4. 'alternativeUrl' must be the direct official product link for that 3rd party alternative.

For 'proTips', provide a concise summary and a detailed 2-3 sentence technical explanation.
Ensure the advice is technical and specific to achieving the '${effect}' goal in the context of ${genre} music.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          introduction: {
            type: Type.STRING,
            description: "A short technical overview of why this chain is selected."
          },
          chain: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING, description: "The exact name of the STOCK plugin in the DAW." },
                category: { type: Type.STRING },
                icon: { type: Type.STRING, description: "One of: eq, comp, reverb, delay, dist, util, limiting" },
                purpose: { type: Type.STRING },
                isStock: { type: Type.BOOLEAN },
                alternative: { type: Type.STRING, description: "A high-end 3rd party alternative plugin." },
                alternativeUrl: { type: Type.STRING, description: "The direct URL to the alternative plugin's website." },
                settings: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      knob: { type: Type.STRING },
                      value: { type: Type.STRING }
                    },
                    required: ["knob", "value"]
                  }
                }
              },
              required: ["id", "name", "category", "icon", "purpose", "isStock", "settings", "alternative", "alternativeUrl"]
            }
          },
          proTips: {
            type: Type.ARRAY,
            items: { 
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["summary", "explanation"]
            }
          }
        },
        required: ["introduction", "chain", "proTips"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

export const analyzeMix = async (
  audioBase64: string,
  genre: AnalysisGenre,
  goal: AnalysisGoal
): Promise<MixAnalysisReport> => {
  const seed = generateSeed(audioBase64, genre, goal);

  const prompt = `Analyze this audio file as a world-class professional mixing and mastering engineer.
Genre Context: ${genre}
Target Delivery: ${goal}

Your objective is to provide a consistent, technical, and objective evaluation of the mix. 
Follow industry standard frequency targets for ${genre}.

JSON Structure:
{
  "summary": "Overall technical impression.",
  "frequencyAnalysis": {
    "description": "General balance overview.",
    "lowEnd": "Sub/Kick assessment.",
    "mids": "Vocal/Instrument clarity.",
    "highs": "Transient air/crispness."
  },
  "stereoImaging": {
    "width": "Technical field observation.",
    "monoCompatibility": "Phase/Mono check."
  },
  "dynamicsAndLoudness": {
    "perceivedLoudness": "LUFS/Weight observations.",
    "dynamicRange": "Compression/Headroom assessment."
  },
  "technicalDirectives": [
    "List 4-5 specific technical suggestions."
  ]
}`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/wav",
            data: audioBase64
          }
        },
        {
          text: prompt
        }
      ]
    },
    config: {
      seed: seed,
      systemInstruction: "You are a precise, objective, and consistent professional mixing engineer. Your analysis is based on established technical standards for professional audio production. You prioritize consistency: when given the same audio and targets, your engineering judgment remains firm and repeatable. Focus on decibels, frequency ranges (Hz/kHz), and stereo correlation rather than abstract metaphors.",
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 15000 }
    }
  });

  return JSON.parse(response.text.trim());
};

export const getScaleAnalysis = async (key: MusicalKey, type: MusicalScaleType): Promise<ScaleAnalysis> => {
  const prompt = `You are a music theory expert specializing in electronic music composition.
Provide a detailed breakdown for the scale: ${key} ${type}.

Requirements:
1. 'notes': Array of note names in the scale (e.g., ['C', 'D', 'E', ...]).
2. 'pianoIndices': Array of integers (0-11) representing the notes on a piano where 0=C, 1=C#, 2=D, etc.
3. 'chords': An array of 7 diatonic chords for the scale.
4. 'description': A concise theory-based description of the scale's characteristic.
5. 'electronicUse': How this scale is typically used in electronic music (e.g., 'Popular in Melodic House for its uplifting yet emotional feel').

JSON Structure:
{
  "notes": string[],
  "pianoIndices": number[],
  "chords": [
    { "numeral": "I", "name": "C Major", "notes": ["C", "E", "G"], "type": "Major", "mood": "Uplifting" },
    ...
  ],
  "description": string,
  "electronicUse": string
}`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          notes: { type: Type.ARRAY, items: { type: Type.STRING } },
          pianoIndices: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          description: { type: Type.STRING },
          electronicUse: { type: Type.STRING },
          chords: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                numeral: { type: Type.STRING },
                name: { type: Type.STRING },
                notes: { type: Type.ARRAY, items: { type: Type.STRING } },
                type: { type: Type.STRING },
                mood: { type: Type.STRING }
              },
              required: ["numeral", "name", "notes", "type", "mood"]
            }
          }
        },
        required: ["notes", "pianoIndices", "description", "electronicUse", "chords"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

