// @ts-ignore
import MidiWriter from 'https://esm.sh/midi-writer-js';

export const ScalesChords: React.FC = () => {
  const [selectedKey, setSelectedKey] = useState<MusicalKey>('C');
  const [selectedType, setSelectedType] = useState<MusicalScaleType>('Minor (Natural)');
  const [analysis, setAnalysis] = useState<ScaleAnalysis | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleGenerate = async () => {
    setIsLoading(true);
    try {
      const result = await getScaleAnalysis(selectedKey, selectedType);
      setAnalysis(result);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleExportMidi = () => {
    if (!analysis) return;

    try {
      const track = new MidiWriter.Track();

      // Set Tempo (Optional, defaults to 128)
      track.setTempo(124);
      track.addEvent(new MidiWriter.ProgramChangeEvent({ instrument: 1 }));

      // Add each chord as a 1-bar block
      analysis.chords.forEach((chord) => {
        // We append '4' to the notes to set a default octave for the MIDI file
        const pitches = chord.notes.map(note => {
          // Clean note names (Gemini sometimes adds extra info)
          const cleanNote = note.split(' ')[0].replace(/[^a-zA-Z#]/g, '');
          return `${cleanNote}4`;
        });

        track.addEvent(new MidiWriter.NoteEvent({
          pitch: pitches,
          duration: '1', // 1 bar
          velocity: 100
        }));
      });

      const write = new MidiWriter.Writer(track);
      const blob = new Blob([write.buildFile()], { type: 'audio/midi' });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `MixBrain_${selectedKey}_${selectedType.replace(/\s+/g, '_')}_Chords.mid`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error("MIDI Export failed:", error);
      alert("Failed to generate MIDI file. Check console for details.");
    }
  };

  const pianoKeys = [
