            {MUSICAL_KEYS.map(k => (
              <button
                key={k}
                onClick={() => setSelectedKey(k)}
                className={`min-w-[34px] py-1.5 rounded font-bold transition-all border text-[10px] ${selectedKey === k ? 'bg-[#ff007f] border-[#ff007f] text-white shadow-[0_0_15px_rgba(255,0,127,0.3)]' : 'bg-black border-white/10 text-white/40 hover:text-white'}`}
              >
                {k}
              </button>
            ))}
          </div>
        </div>
        <div className="space-y-2">
