            className="w-full bg-black border border-white/10 rounded-lg px-4 py-3 text-sm focus:border-[#ff007f] outline-none text-white font-bold"
          >
            {SCALE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <div className="md:col-span-2 lg:col-span-1">
          <button
            onClick={handleGenerate}
            disabled={isLoading}
            className={`w-full py-3 rounded-lg font-black uppercase tracking-widest text-xs transition-all active:scale-95 border-2 ${
