import React, { useState, useRef } from 'react';
import { AnalysisGenre, AnalysisGoal, MixAnalysisReport } from '../types';
import { analyzeMix } from '../services/geminiService';

const ANALYSIS_GENRES: AnalysisGenre[] = ['House', 'EDM', 'Trance', 'Garage', 'Pop', 'Commercial'];
const ANALYSIS_GOALS: AnalysisGoal[] = ['Club-Ready Track', 'Radio', 'Streaming platforms', 'Pre-Master Mix'];

// Increased to allow for large studio files, but with advice.
const MAX_FILE_SIZE_MB = 200; 
const OPTIMAL_SIZE_MB = 20;

export const MixAnalyzer: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [genre, setGenre] = useState<AnalysisGenre>('House');
  const [goal, setGoal] = useState<AnalysisGoal>('Club-Ready Track');
  const [isLoading, setIsLoading] = useState(false);
  const [report, setReport] = useState<MixAnalysisReport | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      const fileSizeMB = selectedFile.size / (1024 * 1024);
      const ext = selectedFile.name.split('.').pop()?.toLowerCase();

      if (ext !== 'wav' && ext !== 'mp3') {
        setError("Only .wav or .mp3 files are supported for professional analysis.");
        setFile(null);
        return;
      }

      if (fileSizeMB > MAX_FILE_SIZE_MB) {
        setError(`File exceeds system limits (${fileSizeMB.toFixed(0)}MB). Max allowed is ${MAX_FILE_SIZE_MB}MB.`);
        setFile(null);
        return;
      }

      setFile(selectedFile);
      setError(null);
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const runAnalysis = async () => {
    if (!file) return;
    setIsLoading(true);
    setError(null);
    setReport(null);
    try {
      const base64 = await fileToBase64(file);
      const mimeType = file.type || (file.name.endsWith('.mp3') ? 'audio/mpeg' : 'audio/wav');
      const result = await analyzeMix(base64, mimeType, genre, goal);
      setReport(result);
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes('413')) {
        setError("Payload too large. The API cannot process a raw file of this size. Please upload a 60s snippet or a high-quality MP3.");
      } else {
        setError("Analysis engine failure. For large tracks, we recommend uploading a high-impact 60-second WAV snippet or an MP3.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const isLargeFile = file && (file.size / (1024 * 1024)) > OPTIMAL_SIZE_MB;

  return (
    <div className="max-w-4xl mx-auto w-full p-8 space-y-8 pb-32">
      <div className="text-center space-y-2">
        <h2 className="text-xs font-black text-[#ff007f] uppercase tracking-[0.4em]">Professional Mix Analysis</h2>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Studio Grade Feedback</h1>
        <p className="text-white/40 text-sm max-w-lg mx-auto">
          Upload your mix for evaluation. Supports .wav and .mp3 (Max 200MB).
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-white/5 p-8 rounded-2xl border border-white/10">
        <div className="space-y-4">
          <div className="block">
            <span className="text-[10px] font-black uppercase tracking-widest text-[#ff007f] mb-2 block italic">Source File (.wav / .mp3)</span>
            <label 
              htmlFor="mix-upload"
              className={`border-2 border-dashed rounded-xl p-8 transition-all cursor-pointer flex flex-col items-center justify-center gap-3 ${file ? 'border-[#00ffff] bg-[#00ffff]/5' : 'border-white/10 hover:border-[#ff007f]/50 hover:bg-white/5'}`}
            >
              <svg className={`w-8 h-8 ${file ? 'text-[#00ffff]' : 'text-white/20'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
              </svg>
              <span className="text-xs font-bold uppercase tracking-widest text-white/60 text-center truncate max-w-full px-2">
                {file ? `${file.name} (${(file.size / (1024 * 1024)).toFixed(1)}MB)` : 'Click to Select Mix'}
              </span>
              <input 
                id="mix-upload"
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept=".wav,.mp3,audio/wav,audio/mpeg"
                onClick={(e) => { (e.target as HTMLInputElement).value = ''; }}
              />
            </label>

            {isLargeFile && (
              <div className="mt-4 p-4 rounded-lg bg-[#ffff00]/10 border border-[#ffff00]/30 flex gap-3">
