interface AuthSystemProps {
  onAuthSuccess: (user: User) => void;
  onAdminExit: () => void;
}

const STORAGE_KEY = 'mixbrain_users';
const ADMIN_PASS = 'P4u7R0b3rt5';

export const AuthSystem: React.FC<AuthSystemProps> = ({ onAuthSuccess, onAdminExit }) => {
  const [view, setView] = useState<'login' | 'signup' | 'payment' | 'admin_login' | 'admin_panel'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Load users from local storage
  const getUsers = (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  };

  const saveUsers = (users: User[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const users = getUsers();
    if (users.find(u => u.email === email)) {
      setError('User already exists');
      return;
    }
    const newUser: User = { email, password, isPaid: false, isAdmin: false, createdAt: Date.now() };
    saveUsers([...users, newUser]);
    setCurrentUser(newUser);
    setView('payment');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const users = getUsers();
    const user = users.find(u => u.email === email && u.password === password);

    if (user) {
      if (user.isPaid) {
        onAuthSuccess(user);
      } else {
        setCurrentUser(user);
        setView('payment');
      }
    } else {
      setError('Invalid email or password');
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === ADMIN_PASS) {
      setView('admin_panel');
    } else {
      setError('Access Denied: Invalid Administrative Credentials');
    }
  };

  const handlePayment = () => {
    setLoading(true);
    setTimeout(() => {
      if (currentUser) {
        const users = getUsers();
        const updatedUsers = users.map(u => 
          u.email === currentUser.email ? { ...u, isPaid: true } : u
        );
        saveUsers(updatedUsers);
        onAuthSuccess({ ...currentUser, isPaid: true });
      }
      setLoading(false);
    }, 2000);
  };

  const toggleUserPaid = (targetEmail: string) => {
    const users = getUsers();
    const updated = users.map(u => u.email === targetEmail ? { ...u, isPaid: !u.isPaid } : u);
    saveUsers(updated);
    // Refresh admin panel
    setView('admin_login');
    setTimeout(() => setView('admin_panel'), 10);
  };

  const deleteUser = (targetEmail: string) => {
    if (confirm(`Delete user ${targetEmail}?`)) {
      const users = getUsers();
      saveUsers(users.filter(u => u.email !== targetEmail));
      setView('admin_login');
      setTimeout(() => setView('admin_panel'), 10);
    }
  };

  if (view === 'admin_panel') {
    const allUsers = getUsers();
    return (
      <div className="fixed inset-0 z-[200] bg-black p-10 overflow-y-auto">
        <div className="max-w-6xl mx-auto space-y-8">
