              <p className="text-[10px] mono text-white/40 uppercase tracking-widest mt-1">Production User Oversight // Total Accounts: {allUsers.length}</p>
            </div>
            <button onClick={onAdminExit} className="px-6 py-2 border border-[#ff007f] text-[#ff007f] font-black text-xs uppercase hover:bg-[#ff007f] hover:text-white transition-all">Exit Admin</button>
          </div>

          <div className="grid grid-cols-1 gap-4">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="border-b border-white/5">
                  <th className="py-4 text-[10px] font-black uppercase tracking-widest text-[#00ffff]">Email</th>
                  <th className="py-4 text-[10px] font-black uppercase tracking-widest text-[#00ffff]">Created</th>
                  <th className="py-4 text-[10px] font-black uppercase tracking-widest text-[#00ffff]">Status</th>
                  <th className="py-4 text-[10px] font-black uppercase tracking-widest text-[#00ffff] text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {allUsers.map((u, i) => (
                  <tr key={i} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                    <td className="py-4 font-mono text-sm text-white/80">{u.email}</td>
                    <td className="py-4 font-mono text-xs text-white/40">{new Date(u.createdAt).toLocaleDateString()}</td>
                    <td className="py-4">
                      <span className={`text-[9px] font-black uppercase px-2 py-1 rounded border ${u.isPaid ? 'border-[#00ffff] text-[#00ffff] bg-[#00ffff]/10' : 'border-[#ff007f] text-[#ff007f] bg-[#ff007f]/10'}`}>
                        {u.isPaid ? 'Paid Member' : 'Unpaid'}
