                    <td className="py-4 text-right space-x-2">
                      <button onClick={() => toggleUserPaid(u.email)} className="text-[10px] font-black uppercase bg-white/5 border border-white/10 px-3 py-1 hover:border-[#00ffff] hover:text-[#00ffff] transition-all">Toggle Pay</button>
                      <button onClick={() => deleteUser(u.email)} className="text-[10px] font-black uppercase bg-[#ff007f]/10 border border-[#ff007f]/30 px-3 py-1 text-[#ff007f] hover:bg-[#ff007f] hover:text-white transition-all">Revoke</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/80 backdrop-blur-xl">
