import React, { useState, useEffect } from 'react';
import { User } from '../types';

interface AuthSystemProps {
  onAuthSuccess: (user: User) => void;
  onAdminExit: () => void;
}

const STORAGE_KEY = 'mixbrain_users';
const ADMIN_PASS = 'P4u7R0b3rt5';

export const AuthSystem: React.FC<AuthSystemProps> = ({ onAuthSuccess, onAdminExit }) => {
  const [view, setView] = useState<'login' | 'signup' | 'payment' | 'admin_login' | 'admin_panel'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [cardNum, setCardNum] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvv, setCvv] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Load users from local storage
  const getUsers = (): User[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  };

  const saveUsers = (users: User[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const users = getUsers();
    if (users.find(u => u.email === email)) {
      setError('User already exists. Please log in.');
      return;
    }
    const newUser: User = { email, password, isPaid: false, isAdmin: false, createdAt: Date.now() };
    saveUsers([...users, newUser]);
    setCurrentUser(newUser);
    setView('payment');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const users = getUsers();
    const user = users.find(u => u.email === email && u.password === password);

    if (user) {
      if (user.isPaid || user.isAdmin) {
        onAuthSuccess(user);
      } else {
        setCurrentUser(user);
        setView('payment');
      }
    } else {
      setError('Invalid production credentials. Access Denied.');
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === ADMIN_PASS) {
      setView('admin_panel');
    } else {
      setError('Access Denied: Invalid Administrative Credentials');
    }
  };

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cardNum || !expiry || !cvv) {
      setError('Please enter valid payment coordinates.');
      return;
    }

    setLoading(true);
    setError('');

    // Simulate payment processing
    setTimeout(() => {
      if (currentUser) {
        const users = getUsers();
        const updatedUsers = users.map(u => 
          u.email === currentUser.email ? { ...u, isPaid: true } : u
        );
        saveUsers(updatedUsers);
        onAuthSuccess({ ...currentUser, isPaid: true });
      }
      setLoading(false);
    }, 2500);
  };

  const toggleUserPaid = (targetEmail: string) => {
    const users = getUsers();
    const updated = users.map(u => u.email === targetEmail ? { ...u, isPaid: !u.isPaid } : u);
    saveUsers(updated);
    // Trigger re-render of panel
    setError('Status Updated'); 
    setTimeout(() => setError(''), 2000);
  };

  const deleteUser = (targetEmail: string) => {
    if (confirm(`Revoke all access for user: ${targetEmail}?`)) {
      const users = getUsers();
      saveUsers(users.filter(u => u.email !== targetEmail));
      setError('User Revoked');
      setTimeout(() => setError(''), 2000);
    }
  };

  if (view === 'admin_panel') {
    const allUsers = getUsers();
    return (
      <div className="fixed inset-0 z-[200] bg-black p-10 overflow-y-auto font-['Inter']">
        <div className="max-w-6xl mx-auto space-y-8">
          <div className="flex justify-between items-center border-b border-white/10 pb-6">
            <div>
              <h1 className="text-3xl font-black italic text-[#ff007f] uppercase tracking-tighter">Admin Control Terminal</h1>
              <p className="text-[10px] font-mono text-white/40 uppercase tracking-widest mt-1">Production User Oversight // System Status: Active</p>
            </div>
            <div className="flex gap-4 items-center">
              {error && <span className="text-[10px] font-black text-[#00ffff] uppercase animate-pulse">{error}</span>}
              <button onClick={onAdminExit} className="px-6 py-2 border border-[#ff007f] text-[#ff007f] font-black text-xs uppercase hover:bg-[#ff007f] hover:text-white transition-all">Exit Admin</button>
            </div>
          </div>

          <div className="bg-white/5 border border-white/10 rounded-2xl overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/5">
                  <th className="p-6 text-[10px] font-black uppercase tracking-widest text-[#00ffff]">Production Email</th>
                  <th className="p-6 text-[10px] font-black uppercase tracking-widest text-[#00ffff]">Registration Date</th>
                  <th className="p-6 text-[10px] font-black uppercase tracking-widest text-[#00ffff]">License Status</th>
                  <th className="p-6 text-[10px] font-black uppercase tracking-widest text-[#00ffff] text-right">Directives</th>
                </tr>
              </thead>
              <tbody>
                {allUsers.length === 0 ? (
                  <tr><td colSpan={4} className="p-20 text-center text-white/20 uppercase font-black tracking-widest italic">No Registered Users in Core</td></tr>
                ) : (
                  allUsers.map((u, i) => (
                    <tr key={i} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                      <td className="p-6 font-mono text-sm text-white/80">{u.email}</td>
                      <td className="p-6 font-mono text-xs text-white/40">{new Date(u.createdAt).toLocaleDateString()}</td>
                      <td className="p-6">
                        <span className={`text-[9px] font-black uppercase px-3 py-1 rounded border ${u.isPaid ? 'border-[#00ffff] text-[#00ffff] bg-[#00ffff]/10' : 'border-[#ff007f] text-[#ff007f] bg-[#ff007f]/10'}`}>
                          {u.isPaid ? 'Licensed Member' : 'Pending Payment'}
                        </span>
                      </td>
                      <td className="p-6 text-right space-x-2">
                        <button onClick={() => toggleUserPaid(u.email)} className="text-[10px] font-black uppercase bg-white/5 border border-white/10 px-4 py-2 hover:border-[#00ffff] hover:text-[#00ffff] transition-all">
                          {u.isPaid ? 'Downgrade' : 'Whitelist'}
                        </button>
                        <button onClick={() => deleteUser(u.email)} className="text-[10px] font-black uppercase bg-[#ff007f]/10 border border-[#ff007f]/30 px-4 py-2 text-[#ff007f] hover:bg-[#ff007f] hover:text-white transition-all">Purge</button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/80 backdrop-blur-xl">
      <div className="w-full max-w-md bg-[#0d0d0d] border border-white/10 p-10 rounded-2xl shadow-[0_0_80px_rgba(0,0,0,1)] relative overflow-hidden animate-in zoom-in-95 duration-300">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-[#ff007f] via-[#00ffff] to-[#ff007f]"></div>

        {view === 'payment' ? (
          <form onSubmit={handlePayment} className="space-y-8">
            <div className="text-center space-y-2">
              <h2 className="text-[10px] font-black text-[#00ffff] uppercase tracking-[0.4em]">Activation Required</h2>
              <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter">Full Studio License</h1>
              <p className="text-white/40 text-xs">Unlock professional mixing chains, harmonic analysis, and cloud-based AI mastering.</p>
            </div>

            <div className="p-6 rounded-xl bg-white/5 border border-white/10 space-y-6">
              <div className="flex justify-between items-center">
                <span className="text-xs font-bold text-white/60">Professional License</span>
                <span className="text-xl font-black text-[#00ffff]">$49.00 <span className="text-[10px] text-white/30 font-normal">USD</span></span>
              </div>

              <div className="space-y-4">
                <div className="space-y-1">
                   <label className="text-[9px] font-black text-white/40 uppercase tracking-widest">Card Number</label>
