                    required
                    type="text"
                    placeholder="4242 4242 4242 4242" 
                    value={cardNum}
                    onChange={(e) => setCardNum(e.target.value)}
                    className="w-full bg-black border border-white/10 rounded p-3 text-sm text-white font-mono focus:border-[#00ffff] outline-none" 
                   />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1">
                    <label className="text-[9px] font-black text-white/40 uppercase tracking-widest">Expiry</label>
                    <input 
                      required
                      type="text"
                      placeholder="MM/YY" 
                      value={expiry}
                      onChange={(e) => setExpiry(e.target.value)}
                      className="bg-black border border-white/10 rounded p-3 text-sm text-white font-mono focus:border-[#00ffff] outline-none w-full" 
                    />
                   </div>
                   <div className="space-y-1">
                    <label className="text-[9px] font-black text-white/40 uppercase tracking-widest">CVV</label>
                    <input 
                      required
                      type="password"
                      placeholder="***" 
                      value={cvv}
                      onChange={(e) => setCvv(e.target.value)}
                      className="bg-black border border-white/10 rounded p-3 text-sm text-white font-mono focus:border-[#00ffff] outline-none w-full" 
                    />
                   </div>
                </div>
              </div>
            </div>

            {error && <p className="text-[#ff007f] text-[10px] font-bold uppercase text-center tracking-widest">{error}</p>}

            <button 
              type="submit"
              disabled={loading}
              className={`w-full py-4 font-black uppercase tracking-[0.2em] text-xs italic border transition-all ${loading ? 'bg-white/5 border-white/10 text-white/20' : 'bg-[#ff007f] text-white border-[#ff007f] hover:bg-black hover:text-[#ff007f]'}`}
            >
              {loading ? 'Validating Terminal...' : 'Activate License'}
            </button>
            <p className="text-[8px] text-white/20 text-center uppercase tracking-widest">Secure 256-Bit Encrypted Transaction</p>
          </form>
        ) : (
          <form onSubmit={view === 'admin_login' ? handleAdminLogin : view === 'signup' ? handleSignup : handleLogin} className="space-y-8">
            <div className="text-center space-y-2">
              <h2 className="text-[10px] font-black text-[#ff007f] uppercase tracking-[0.4em]">
                {view === 'admin_login' ? 'System Restricted' : 'Secure Authorization'}
              </h2>
              <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter">
                {view === 'admin_login' ? 'Admin Access' : view === 'signup' ? 'Create Account' : 'Welcome Back'}
              </h1>
            </div>

            <div className="space-y-4">
              {view !== 'admin_login' && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-white/40 uppercase tracking-widest">Production Email</label>
                  <input 
                    required 
                    type="email" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full bg-black border border-white/10 rounded p-3 text-sm text-white focus:border-[#ff007f] outline-none" 
                    placeholder="engineer@studio.com"
                  />
                </div>
              )}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-white/40 uppercase tracking-widest">
                  {view === 'admin_login' ? 'Root Access Key' : 'Security Password'}
                </label>
                <input 
                  required 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-black border border-white/10 rounded p-3 text-sm text-white focus:border-[#ff007f] outline-none"
                  placeholder="••••••••"
                />
              </div>
            </div>

            {error && <p className="text-[#ff007f] text-[10px] font-bold uppercase text-center tracking-widest">{error}</p>}

            <button type="submit" className="w-full py-4 bg-[#ff007f] text-white font-black uppercase tracking-[0.2em] text-xs italic hover:bg-black border border-[#ff007f] transition-all">
              {view === 'admin_login' ? 'Override Access' : view === 'signup' ? 'Initialize Account' : 'Authorize Session'}
            </button>

            <div className="flex flex-col gap-3 pt-4 border-t border-white/5">
              {view === 'login' ? (
                <button type="button" onClick={() => setView('signup')} className="text-[9px] text-white/40 uppercase font-bold tracking-widest hover:text-white transition-colors">New Producer? Initialize Access</button>
              ) : view === 'signup' ? (
                <button type="button" onClick={() => setView('login')} className="text-[9px] text-white/40 uppercase font-bold tracking-widest hover:text-white transition-colors">Existing Member? Authorize Session</button>
              ) : (
                <button type="button" onClick={() => setView('login')} className="text-[9px] text-white/40 uppercase font-bold tracking-widest hover:text-white transition-colors">Standard Authorization</button>
              )}

              {view !== 'admin_login' && (
                <button type="button" onClick={() => setView('admin_login')} className="text-[9px] text-[#00ffff] uppercase font-bold tracking-widest hover:underline transition-colors opacity-50 hover:opacity-100">Administrative Overload</button>
              )}
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

