import React, { useState, useEffect } from 'react';
import { User } from '../types';

interface AuthSystemProps {
  onAuthSuccess: (user: User) => void;
  onAdminExit: () => void;
}

const STORAGE_KEY_CODE = 'mixbrain_access_code';
const STORAGE_KEY_USERS = 'mixbrain_logged_users';
const DEFAULT_ACCESS_CODE = 'M1xBr41n!@';
const ADMIN_MASTER_PASS = 'P4u7R0b3rt5';

export const AuthSystem: React.FC<AuthSystemProps> = ({ onAuthSuccess, onAdminExit }) => {
  const [view, setView] = useState<'entry' | 'admin_login' | 'admin_panel'>('entry');
  const [name, setName] = useState('');
  const [accessCode, setAccessCode] = useState('');
  const [adminPass, setAdminPass] = useState('');
  const [newAccessCode, setNewAccessCode] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Get current code from storage or default
  const getCurrentCode = (): string => {
    return localStorage.getItem(STORAGE_KEY_CODE) || DEFAULT_ACCESS_CODE;
  };

  const handleEntry = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const currentCode = getCurrentCode();
    if (accessCode.trim() === currentCode) {
      const newUser: User = { 
        name: name.trim() || 'Producer', 
        entryTimestamp: Date.now() 
      };

      // Save for admin tracking
      const users = JSON.parse(localStorage.getItem(STORAGE_KEY_USERS) || '[]');
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify([...users, newUser]));

      onAuthSuccess(newUser);
    } else {
      setError('Invalid Access Credentials. System Restricted.');
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPass === ADMIN_MASTER_PASS) {
      setView('admin_panel');
      setNewAccessCode(getCurrentCode());
    } else {
      setError('Administrative Access Denied.');
    }
  };

  const updateAccessCode = () => {
    if (!newAccessCode.trim()) {
      setError('New code cannot be empty.');
      return;
    }
    localStorage.setItem(STORAGE_KEY_CODE, newAccessCode.trim());
    setSuccess('Access Code Updated Successfully.');
    setTimeout(() => setSuccess(''), 3000);
  };

  const clearLogs = () => {
    if (confirm('Clear all production logs?')) {
      localStorage.removeItem(STORAGE_KEY_USERS);
      setSuccess('Logs Purged.');
      setTimeout(() => setSuccess(''), 3000);
    }
  };

  if (view === 'admin_panel') {
    const users = JSON.parse(localStorage.getItem(STORAGE_KEY_USERS) || '[]');
    return (
      <div className="fixed inset-0 z-[200] bg-black p-10 overflow-y-auto font-['Inter']">
        <div className="max-w-4xl mx-auto space-y-10">
          <div className="flex justify-between items-center border-b border-white/10 pb-6">
            <div>
              <h1 className="text-3xl font-black italic text-[#ff007f] uppercase tracking-tighter">System Admin Terminal</h1>
              <p className="text-[10px] font-mono text-white/40 uppercase tracking-widest mt-1">Core Access Control // Root Privileges</p>
            </div>
            <button onClick={onAdminExit} className="px-6 py-2 border border-[#ff007f] text-[#ff007f] font-black text-xs uppercase hover:bg-[#ff007f] hover:text-white transition-all">Terminate Admin Session</button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-white/5 border border-white/10 p-8 rounded-2xl space-y-6">
              <h2 className="text-xs font-black text-[#00ffff] uppercase tracking-widest italic">Update Public Access Code</h2>
              <div className="space-y-4">
                <input 
                  type="text" 
                  value={newAccessCode}
                  onChange={(e) => setNewAccessCode(e.target.value)}
                  className="w-full bg-black border border-white/10 rounded p-4 text-sm text-white focus:border-[#00ffff] outline-none font-mono"
                  placeholder="New Code"
                />
                <button 
                  onClick={updateAccessCode}
                  className="w-full py-4 bg-[#00ffff] text-black font-black uppercase text-xs tracking-widest hover:bg-white transition-colors"
                >
                  Apply New Code
                </button>
                {success && <p className="text-[#00ffff] text-[10px] font-bold uppercase text-center tracking-widest animate-pulse">{success}</p>}
                {error && <p className="text-[#ff007f] text-[10px] font-bold uppercase text-center tracking-widest">{error}</p>}
              </div>
            </div>

            <div className="bg-white/5 border border-white/10 p-8 rounded-2xl space-y-6">
              <h2 className="text-xs font-black text-[#ff007f] uppercase tracking-widest italic">Recent Access Logs</h2>
              <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2">
                {users.length === 0 ? (
                  <p className="text-[10px] text-white/20 uppercase font-black text-center py-10 tracking-widest">No Recent Activity</p>
                ) : (
                  users.slice(-10).reverse().map((u: any, i: number) => (
                    <div key={i} className="flex justify-between items-center p-3 rounded bg-black/40 border border-white/5">
                      <span className="text-xs text-white/80 font-bold">{u.name}</span>
                      <span className="text-[9px] font-mono text-white/30">{new Date(u.entryTimestamp).toLocaleTimeString()}</span>
                    </div>
                  ))
                )}
              </div>
              <button 
                onClick={clearLogs}
                className="w-full py-4 border border-[#ff007f]/50 text-[#ff007f] font-black uppercase text-xs tracking-widest hover:bg-[#ff007f] hover:text-white transition-colors"
              >
                Clear Production Logs
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/90 backdrop-blur-3xl">
      <div className="w-full max-w-md bg-[#0d0d0d] border border-white/10 p-10 rounded-3xl shadow-[0_0_100px_rgba(255,0,127,0.1)] relative overflow-hidden animate-in zoom-in-95 duration-300">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-[#ff007f] via-[#00ffff] to-[#ff007f]"></div>

        {view === 'entry' ? (
          <form onSubmit={handleEntry} className="space-y-10">
            <div className="text-center space-y-3">
              <h2 className="text-[10px] font-black text-[#ff007f] uppercase tracking-[0.5em]">Authorization Required</h2>
              <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">System Access</h1>
              <div className="flex justify-center gap-1 h-1">
                 <div className="w-8 h-full bg-[#ff007f]"></div>
                 <div className="w-4 h-full bg-[#00ffff]"></div>
                 <div className="w-2 h-full bg-white"></div>
              </div>
            </div>

            <div className="space-y-5">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] ml-1">Producer Name</label>
                <input 
                  required
                  type="text"
                  placeholder="ENTER IDENTITY"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-black border border-white/10 rounded-xl p-4 text-sm text-white focus:border-[#ff007f] outline-none font-bold placeholder:text-white/10"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] ml-1">Access Credentials</label>
                <input 
                  required
                  type="password"
                  placeholder="••••••••"
                  value={accessCode}
                  onChange={(e) => setAccessCode(e.target.value)}
                  className="w-full bg-black border border-white/10 rounded-xl p-4 text-sm text-white focus:border-[#00ffff] outline-none font-mono placeholder:text-white/10 tracking-[0.5em]"
                />
              </div>
            </div>

            {error && <p className="text-[#ff007f] text-[10px] font-black uppercase text-center tracking-widest animate-pulse">{error}</p>}

            <button type="submit" className="group relative w-full py-5 bg-[#ff007f] text-white font-black uppercase tracking-[0.3em] text-xs italic hover:bg-black border border-[#ff007f] transition-all overflow-hidden rounded-xl">
               <span className="relative z-10">Initialize Production</span>
               <div className="absolute inset-0 translate-y-full group-hover:translate-y-0 bg-black transition-transform duration-300"></div>
            </button>

            <div className="text-center pt-4 border-t border-white/5">
              <button 
                type="button" 
                onClick={() => setView('admin_login')}
                className="text-[9px] text-white/20 uppercase font-black tracking-widest hover:text-[#00ffff] transition-colors"
              >
                Administrative Overload
              </button>
            </div>
          </form>
        ) : (
          <form onSubmit={handleAdminLogin} className="space-y-10">
            <div className="text-center space-y-3">
              <h2 className="text-[10px] font-black text-[#00ffff] uppercase tracking-[0.5em]">System Override</h2>
              <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter">Root Login</h1>
            </div>

            <div className="space-y-2">
              <label className="text-[9px] font-black text-white/30 uppercase tracking-[0.3em] ml-1">Master Access Key</label>
              <input 
                required
                type="password"
                placeholder="ROOT PASSWORD"
                value={adminPass}
                onChange={(e) => setAdminPass(e.target.value)}
                className="w-full bg-black border border-white/10 rounded-xl p-4 text-sm text-white focus:border-[#00ffff] outline-none font-mono placeholder:text-white/10 tracking-[0.5em]"
              />
            </div>

            {error && <p className="text-[#ff007f] text-[10px] font-black uppercase text-center tracking-widest">{error}</p>}

            <button type="submit" className="w-full py-5 bg-[#00ffff] text-black font-black uppercase tracking-[0.3em] text-xs italic hover:bg-black hover:text-[#00ffff] border border-[#00ffff] transition-all rounded-xl">
               Execute Root Entry
            </button>

            <div className="text-center pt-4 border-t border-white/5">
              <button 
                type="button" 
                onClick={() => setView('entry')}
                className="text-[9px] text-white/20 uppercase font-black tracking-widest hover:text-white transition-colors"
              >
                Return to Entry Terminal
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

