import { GoogleGenAI, Type } from "@google/genai";
import { SelectionState, ProductionGuidance, MixAnalysisReport, AnalysisGenre, AnalysisGoal, ScaleAnalysis, MusicalKey, MusicalScaleType } from "../types";

// Always use the named parameter and direct process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const generateSeed = (audioBase64: string, genre: string, goal: string): number => {
  const identityString = audioBase64.substring(0, 5000) + genre + goal;
  let hash = 0;
  for (let i = 0; i < identityString.length; i++) {
    const char = identityString.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash |= 0; 
  }
  return Math.abs(hash);
};

export const getProductionGuidance = async (state: SelectionState): Promise<ProductionGuidance> => {
  const { daw, genre, area, effect } = state;

  const prompt = `You are a world-class electronic music mix engineer and an expert in ${daw}.
Generate professional mixing guidance for:
DAW: ${daw}
Genre: ${genre}
Area: ${area}
Effect Goal: ${effect}

CRITICAL REQUIREMENT: The primary plugin 'chain' MUST use ONLY the built-in stock plugins provided by ${daw}. 
For each plugin in the chain:
1. 'name' must be the exact name of the stock plugin in ${daw} (e.g., 'Compressor', 'EQ Eight', 'Phat FX').
2. 'isStock' must be true.
3. 'alternative' must be a high-end 3rd party professional alternative (e.g., FabFilter Pro-Q 3, Soundtoys Decapitator, Waves SSL G-Master Buss Compressor).
4. 'alternativeUrl' must be the direct official product link for that 3rd party alternative.

For 'proTips', provide a concise summary and a detailed 2-3 sentence technical explanation.
Ensure the advice is technical and specific to achieving the '${effect}' goal in the context of ${genre} music.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          introduction: {
            type: Type.STRING,
            description: "A short technical overview of why this chain is selected."
          },
          chain: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING, description: "The exact name of the STOCK plugin in the DAW." },
                category: { type: Type.STRING },
                icon: { type: Type.STRING, description: "One of: eq, comp, reverb, delay, dist, util, limiting" },
                purpose: { type: Type.STRING },
                isStock: { type: Type.BOOLEAN },
                alternative: { type: Type.STRING, description: "A high-end 3rd party alternative plugin." },
                alternativeUrl: { type: Type.STRING, description: "The direct URL to the alternative plugin's website." },
                settings: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      knob: { type: Type.STRING },
                      value: { type: Type.STRING }
                    },
                    required: ["knob", "value"]
                  }
                }
              },
              required: ["id", "name", "category", "icon", "purpose", "isStock", "settings", "alternative", "alternativeUrl"]
            }
          },
          proTips: {
            type: Type.ARRAY,
            items: { 
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["summary", "explanation"]
            }
          }
        },
        required: ["introduction", "chain", "proTips"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

export const analyzeMix = async (
  audioBase64: string,
  mimeType: string,
  genre: AnalysisGenre,
  goal: AnalysisGoal
): Promise<MixAnalysisReport> => {
  const seed = generateSeed(audioBase64, genre, goal);

  const prompt = `Analyze this ${mimeType} audio file as a world-class professional mixing and mastering engineer.
Genre Context: ${genre}
Target Delivery: ${goal}

Objective technical feedback required. Focus on spectral balance, stereo width, and RMS/LUFS dynamics.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: mimeType,
            data: audioBase64
          }
        },
        {
          text: prompt
        }
      ]
    },
    config: {
      seed: seed,
      systemInstruction: "You are a professional mixing engineer. Analyze the audio data provided. If the file is a long track, focus on the overall spectral signature. Provide specific dB and Hz values in your report.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          frequencyAnalysis: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              lowEnd: { type: Type.STRING },
              mids: { type: Type.STRING },
              highs: { type: Type.STRING }
            },
            required: ["description", "lowEnd", "mids", "highs"]
          },
          stereoImaging: {
            type: Type.OBJECT,
            properties: {
              width: { type: Type.STRING },
              monoCompatibility: { type: Type.STRING }
            },
            required: ["width", "monoCompatibility"]
          },
          dynamicsAndLoudness: {
            type: Type.OBJECT,
            properties: {
              perceivedLoudness: { type: Type.STRING },
              dynamicRange: { type: Type.STRING }
            },
            required: ["perceivedLoudness", "dynamicRange"]
          },
          technicalDirectives: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "frequencyAnalysis", "stereoImaging", "dynamicsAndLoudness", "technicalDirectives"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

export const getScaleAnalysis = async (key: MusicalKey, type: MusicalScaleType): Promise<ScaleAnalysis> => {
  const prompt = `You are a music theory expert specializing in electronic music production.
Provide a technical breakdown for the scale: ${key} ${type}.

MANDATORY REQUIREMENTS for JSON:
1. 'notes': String names of notes in the scale (e.g., ["C", "D", "Eb"...]).
2. 'pianoIndices': Array of integers from 0 to 11 representing the notes on a piano keyboard starting from C (0=C, 1=C#, 2=D, 3=D#, 4=E, 5=F, 6=F#, 7=G, 8=G#, 9=A, 10=A#, 11=B).
3. 'description': Emotional and technical description of the scale.
4. 'electronicUse': Specific examples of how this scale is used in Electronic Dance Music (e.g. Techno, House, Trance).
5. 'chords': The 7 diatonic chords of the scale.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          notes: { type: Type.ARRAY, items: { type: Type.STRING } },
          pianoIndices: { 
            type: Type.ARRAY, 
            items: { type: Type.NUMBER },
            description: "Integers 0-11 mapping to C, C#, D, D#, E, F, F#, G, G#, A, A#, B"
          },
          description: { type: Type.STRING },
          electronicUse: { type: Type.STRING },
          chords: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                numeral: { type: Type.STRING },
                name: { type: Type.STRING },
                notes: { type: Type.ARRAY, items: { type: Type.STRING } },
                type: { type: Type.STRING },
                mood: { type: Type.STRING }
              },
              required: ["numeral", "name", "notes", "type", "mood"]
            }
          }
        },
        required: ["notes", "pianoIndices", "description", "electronicUse", "chords"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

